import type { Icons } from '@beeline/design-tokens/js/iconfont/icons';
import type { ReactElement, ReactNode } from 'react';
export interface BreadcrumbsProps {
    /** Признак свёрнут / развёрнут */
    collapsed?: boolean;
    /** Пользовательский класс*/
    className?: string;
    /** Хлебные крошки, можно использовать BreadcrumbsItem, а можно свои кастомные*/
    children?: ReactNode | ReactNode[];
    /** Массив, из которого строятся хлебные крошки (BreadcrumbsItem). Можно использовать или children или value */
    value?: BreadcrumbsItemProps[];
}
export interface BreadcrumbsItemProps {
    label: string;
    href?: string;
    /**
     * Компонент ссылки для SPA-навигации.
     * Если задан, элемент будет отрисован как routedLink через Typography.
     * При одновременном указании href и routingComponent приоритет имеет routingComponent.
     */
    routingComponent?: ReactElement;
    tooltipText?: string;
    menu?: {
        items: BreadcrumbsItemMenu[];
        isOpen: boolean;
        onOutsideClick: () => void;
        onItemClick: () => void;
    };
    currentPage?: boolean;
    index?: string;
}
export interface BreadcrumbsItemMenu {
    title: string;
    subtitle?: string;
    iconName?: Icons;
    onClick?: () => void;
    disabled?: boolean;
}
